@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Serif:wght@400;500;600;700&family=Inter:wght@300;400;500;600;700;800;900&family=JetBrains+Mono:wght@400;500;600;700&display=swap');

:root {
  --bg-primary: #0A0D14;
  --surface-0: #0D1017;
  --surface-1: #121725;
  --surface-2: #161C2E;
  --text-primary: #EEF2FF;
  --text-secondary: #9AA3B2;
  --text-tertiary: #6B7280;
  --blue-primary: #4F86F7;
  --blue-deep: #2F5FD6;
  --green-profit: #34D399;
  --green-dark: #10B981;
  --red-loss: #EF4444;
  --gold-pro: #F59E0B;
  --stroke-subtle: rgba(255, 255, 255, 0.08);
  --stroke-muted: rgba(255, 255, 255, 0.12);
  --font-serif: 'IBM Plex Serif', Georgia, serif;
  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-mono: 'JetBrains Mono', 'SF Mono', monospace;

  font-family: var(--font-sans);
  line-height: 1.5;
  font-weight: 400;
  color-scheme: dark;
  color: var(--text-primary);
  background-color: var(--bg-primary);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  margin: 0;
  min-width: 320px;
  min-height: 100vh;
  background-color: var(--bg-primary);
}

#root {
  width: 100%;
  min-height: 100vh;
}

.font-serif {
  font-family: var(--font-serif);
}

.font-mono {
  font-family: var(--font-mono);
}

input, button, textarea, select {
  font-family: inherit;
}

