export default function WeeklySummary({ onBack, stats, weekData }) {
  const record = weekData?.record || stats?.record || '0-0';
  const [wins, losses] = record.split('-').map(Number);
  const totalPicks = (wins || 0) + (losses || 0);
  const passDays = weekData?.passes || 7 - totalPicks;
  const selectivity = totalPicks > 0 ? Math.round((totalPicks / 7) * 100) : 0;
  const pnl = weekData?.pnl || 0;

  return (
    <div style={{ padding: '0', paddingBottom: '100px' }}>
      <div style={{
        padding: '16px 20px',
        display: 'flex', alignItems: 'center', gap: '12px',
      }}>
        <button onClick={onBack} style={{
          background: 'none', border: 'none', cursor: 'pointer',
          color: 'var(--text-secondary)', padding: '4px',
        }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M19 12H5M12 19l-7-7 7-7"/>
          </svg>
        </button>
        <span style={{
          fontFamily: 'var(--font-sans)', fontSize: '16px', fontWeight: 600,
          color: 'var(--text-primary)',
        }}>Weekly Summary</span>
      </div>

      <div style={{ padding: '0 20px' }}>
        <div style={{
          fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 600,
          letterSpacing: '2px', textTransform: 'uppercase',
          color: 'var(--text-tertiary)', marginBottom: '10px',
        }}>Week in Review</div>

        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '20px',
          border: '1px solid var(--stroke-subtle)', padding: '24px',
          marginBottom: '16px', textAlign: 'center',
        }}>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '48px', fontWeight: 800,
            color: pnl >= 0 ? 'var(--green-profit)' : 'var(--red-loss)',
            lineHeight: '1', marginBottom: '8px',
          }}>
            {pnl >= 0 ? '+' : ''}{pnl}u
          </div>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '13px',
            color: 'var(--text-secondary)',
          }}>
            {record} record this week
          </div>
        </div>

        <div style={{
          display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '12px',
          marginBottom: '16px',
        }}>
          <StatCard value={totalPicks} label="Picks" />
          <StatCard value={passDays} label="Passes" />
          <StatCard value={`${selectivity}%`} label="Selectivity" />
        </div>

        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '16px',
          border: '1px solid var(--stroke-subtle)', padding: '20px',
          marginBottom: '16px',
        }}>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 600,
            letterSpacing: '2px', textTransform: 'uppercase',
            color: 'var(--text-tertiary)', marginBottom: '12px',
          }}>Daily Log</div>

          {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map((day, i) => {
            const dayData = weekData?.days?.[i];
            const type = dayData?.type || (i < 5 ? 'pass' : 'no_games');
            return (
              <div key={day} style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                padding: '10px 0',
                borderBottom: i < 6 ? '1px solid var(--stroke-subtle)' : 'none',
              }}>
                <span style={{
                  fontFamily: 'var(--font-mono)', fontSize: '13px',
                  color: 'var(--text-secondary)', width: '40px',
                }}>{day}</span>
                <span style={{
                  fontSize: '13px',
                  color: type === 'pick' ? 'var(--text-primary)'
                    : type === 'pass' ? 'var(--text-tertiary)'
                    : 'var(--text-tertiary)',
                  fontWeight: type === 'pick' ? 600 : 400,
                }}>
                  {type === 'pick' ? dayData?.summary || 'Pick published'
                    : type === 'pass' ? 'No qualifying edge'
                    : 'No games'}
                </span>
                {type === 'pick' && dayData?.result && (
                  <span style={{
                    fontFamily: 'var(--font-mono)', fontSize: '12px', fontWeight: 600,
                    color: dayData.result === 'win' ? 'var(--green-profit)' : 'var(--red-loss)',
                  }}>
                    {dayData.result === 'win' ? 'W' : 'L'}
                  </span>
                )}
              </div>
            );
          })}
        </div>

        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '16px',
          border: '1px solid var(--stroke-subtle)', padding: '20px',
          marginBottom: '16px',
        }}>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 600,
            letterSpacing: '2px', textTransform: 'uppercase',
            color: 'var(--green-profit)', marginBottom: '10px',
          }}>Discipline Note</div>
          <p style={{
            fontSize: '14px', color: 'var(--text-secondary)', lineHeight: '1.7',
          }}>
            {passDays >= 5
              ? 'High pass rate this week. The model found few qualifying edges. Restraint preserved capital for better opportunities.'
              : totalPicks > 0 && pnl >= 0
                ? 'Selective picks with positive results. The edge threshold continues to filter out marginal opportunities.'
                : 'Every pass represents a decision not to risk capital without an edge. That discipline compounds over time.'
            }
          </p>
        </div>

        <p style={{
          fontSize: '11px', color: 'var(--text-tertiary)', lineHeight: '1.5',
          textAlign: 'center', padding: '8px 0 16px',
        }}>
          Past performance does not guarantee future results.
        </p>
      </div>
    </div>
  );
}

function StatCard({ value, label }) {
  return (
    <div style={{
      backgroundColor: 'var(--surface-1)', borderRadius: '14px',
      border: '1px solid var(--stroke-subtle)', padding: '16px',
      textAlign: 'center',
    }}>
      <div style={{
        fontFamily: 'var(--font-mono)', fontSize: '22px', fontWeight: 700,
        color: 'var(--text-primary)', marginBottom: '4px',
      }}>{value}</div>
      <div style={{
        fontSize: '10px', fontWeight: 600, color: 'var(--text-tertiary)',
        textTransform: 'uppercase', letterSpacing: '0.08em',
      }}>{label}</div>
    </div>
  );
}

src/components/sharp/DashboardTab.jsx.content:
import { useState, useEffect } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { useApi, apiGet } from '../../hooks/useApi';
import { useSport, sportQuery } from '../../hooks/useSport';
function SectionLabel({ children }) {
  return (
    <div style={{
      fontFamily: 'var(--font-mono)',
      fontSize: '10px', fontWeight: 600,
      letterSpacing: '2px', textTransform: 'uppercase',
      color: 'var(--text-tertiary)',
      marginBottom: '10px',
    }}>{children}</div>
  );
}

export default function DashboardTab({ onNavigate, embedded = false }) {
  const { user } = useAuth();
  const { sport } = useSport();
  const { data: dashData, loading } = useApi(sportQuery('/public/dashboard-stats', sport), { pollInterval: 60000 });
  const { data: calibrationData } = useApi(sportQuery('/public/calibration', sport), { pollInterval: 60000 });

  if (loading) {
    return (
      <div style={{ padding: '20px' }}>
        <DashboardSkeleton />
      </div>
    );
  }

  const perf = dashData?.performance || {};
  const risk = dashData?.risk || {};
  const discipline = dashData?.discipline || {};
  const health = dashData?.model_health || {};
  const recentPicks = dashData?.recent_picks || [];
  const equityCurve = perf.equity_curve || [];
  const buckets = calibrationData?.buckets || [];

  return (
    <div style={{ padding: '0', paddingBottom: embedded ? '0' : '100px' }}>
      {!embedded && (
        <div style={{
          padding: '16px 20px',
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <svg viewBox="0 0 40 40" width="24" height="24" fill="none">
              <path d="M20 4L6 10v10c0 9.2 6 17.4 14 20 8-2.6 14-10.8 14-20V10L20 4z" stroke="white" strokeWidth="1.8" fill="none"/>
              <rect x="12" y="24" width="3" height="6" rx="1" fill="rgba(255,255,255,0.3)"/>
              <rect x="17" y="20" width="3" height="10" rx="1" fill="rgba(255,255,255,0.4)"/>
              <rect x="22" y="22" width="3" height="8" rx="1" fill="rgba(255,255,255,0.35)"/>
              <path d="M11 22L17 16L22 19L30 11" stroke="white" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
              <path d="M26 11h4v4" stroke="white" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
            <span style={{
              fontFamily: 'var(--font-sans)', fontSize: '13px', fontWeight: 700,
              color: 'var(--text-primary)', letterSpacing: '2px', textTransform: 'uppercase',
            }}>Sharp Picks</span>
          </div>
          <ModelHealthBadge health={health} />
        </div>
      )}

      <div style={{ padding: '0 20px' }}>
        {embedded && <ModelHealthBadge health={health} />}

        <PerformanceCore perf={perf} equityCurve={equityCurve} />

        <CalibrationPanel buckets={buckets} health={calibrationData?.health} />

        <RiskProfile risk={risk} />

        <DisciplineScore discipline={discipline} />

        <LatestResultCard picks={recentPicks} />

        <RecentPickLog picks={recentPicks} />

        <p style={{
          fontFamily: 'var(--font-serif)', fontStyle: 'italic',
          fontSize: '13px', color: 'var(--text-secondary)',
          textAlign: 'center', padding: '8px 20px 4px',
          lineHeight: '1.5',
        }}>
          This dashboard measures discipline, not excitement.
        </p>
        <p style={{
          fontSize: '11px', color: 'var(--text-tertiary)', lineHeight: '1.5',
          textAlign: 'center', padding: '0 20px 16px',
        }}>
          Past performance does not guarantee future results. This analysis reflects probabilities, not certainty.
        </p>
      </div>
    </div>
  );
}


function PerformanceCore({ perf, equityCurve }) {
  const pnl = perf.total_pnl || 0;
  const isPositive = pnl >= 0;

  return (
    <>
      <SectionLabel>Model Performance</SectionLabel>
      <div style={{
        backgroundColor: 'var(--surface-1)', borderRadius: '20px',
        border: '1px solid var(--stroke-subtle)', padding: '24px',
        marginBottom: '16px',
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div>
            <div style={{
              fontFamily: 'var(--font-mono)', fontSize: '42px', fontWeight: 800,
              color: isPositive ? 'var(--green-profit)' : 'var(--red-loss)',
              lineHeight: '1', marginBottom: '8px',
            }}>
              {isPositive ? '+' : '-'}${Math.abs(pnl).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}
            </div>
            <div style={{
              fontFamily: 'var(--font-mono)', fontSize: '10px',
              color: 'var(--text-tertiary)', letterSpacing: '0.5px',
              marginBottom: '10px',
            }}>
              Model Only · 1u Standardized · -110 Baseline
            </div>
            <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap' }}>
              <StatChip
                value={`${perf.roi >= 0 ? '+' : ''}${perf.roi || 0}%`}
                label="ROI"
                color={perf.roi >= 0 ? 'var(--green-profit)' : 'var(--red-loss)'}
              />
              <InfoTooltip text="ROI measures efficiency, not streaks. Short samples swing. Long samples tell the truth." />
              <StatChip value={perf.record || '0-0'} label="Record" />
            </div>
          </div>
          {equityCurve.length > 1 && (
            <div style={{ width: '120px', flexShrink: 0 }}>
              <MiniEquityChart data={equityCurve} />
            </div>
          )}
        </div>

        <div style={{
          marginTop: '16px', paddingTop: '14px',
          borderTop: '1px solid var(--stroke-subtle)',
          display: 'flex', gap: '6px', flexWrap: 'wrap',
        }}>
          <MetaTag label="Season" />
          <MetaTag label={`${perf.total_picks || 0} Picks`} />
          <MetaTag label={`${perf.total_passes || 0} Passes`} />
          <MetaTag label={`${perf.selectivity || 0}% Selectivity`} />
        </div>
      </div>
    </>
  );
}


function CalibrationPanel({ buckets, health }) {
  const hasSufficientData = buckets.some(b => b.picks >= 10);

  return (
    <>
      <SectionLabel>Model Integrity</SectionLabel>
      <InfoCallout
        header="Why Calibration Matters"
        text="If a pick is labeled 58%, it should win roughly 58% over time. Calibration is how we verify honesty in the model. Hot streaks impress. Calibration sustains."
      />
      <div style={{
        backgroundColor: 'var(--surface-1)', borderRadius: '20px',
        border: '1px solid var(--stroke-subtle)', padding: '24px',
        marginBottom: '16px',
      }}>
        {buckets.map((bucket, i) => (
          <CalibrationBar key={i} bucket={bucket} />
        ))}

        {!hasSufficientData && (
          <p style={{
            fontSize: '12px', color: 'var(--text-tertiary)',
            lineHeight: '1.5', marginTop: '12px',
          }}>
            Calibration data builds as picks are graded. Minimum 10 picks per bucket for meaningful analysis.
          </p>
        )}
      </div>
    </>
  );
}

function CalibrationBar({ bucket }) {
  const actual = bucket.actual_cover_rate;
  const expected = bucket.expected_midpoint;
  const hasPicks = bucket.picks > 0;
  const maxWidth = 100;
  const expectedWidth = Math.min(expected, maxWidth);
  const actualWidth = actual !== null ? Math.min(actual, maxWidth) : 0;

  const isAligned = bucket.gap !== null && Math.abs(bucket.gap) <= 3;
  const barColor = !hasPicks ? 'var(--text-tertiary)' :
    isAligned ? 'var(--green-profit)' :
    bucket.gap < -3 ? 'var(--red-loss)' : 'var(--gold-pro)';

  return (
    <div style={{ marginBottom: '16px' }}>
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'baseline',
        marginBottom: '6px',
      }}>
        <span style={{
          fontFamily: 'var(--font-mono)', fontSize: '12px',
          color: 'var(--text-secondary)', fontWeight: 600,
        }}>{bucket.bucket}</span>
        <div style={{ display: 'flex', gap: '12px' }}>
          {hasPicks && actual !== null && (
            <span style={{
              fontFamily: 'var(--font-mono)', fontSize: '12px',
              color: barColor, fontWeight: 700,
            }}>Actual: {actual}%</span>
          )}
          <span style={{
            fontFamily: 'var(--font-mono)', fontSize: '11px',
            color: 'var(--text-tertiary)',
          }}>Expected: {expected}%</span>
        </div>
      </div>
      <div style={{
        position: 'relative', height: '6px',
        backgroundColor: 'var(--surface-2)', borderRadius: '3px',
        overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', left: 0, top: 0, height: '100%',
          width: `${expectedWidth}%`,
          backgroundColor: 'rgba(255,255,255,0.06)',
          borderRadius: '3px',
        }} />
        {hasPicks && (
          <div style={{
            position: 'absolute', left: 0, top: 0, height: '100%',
            width: `${actualWidth}%`,
            backgroundColor: barColor,
            borderRadius: '3px',
            opacity: 0.7,
            transition: 'width 0.6s ease',
          }} />
        )}
      </div>
      {!hasPicks && (
        <span style={{
          fontFamily: 'var(--font-mono)', fontSize: '10px',
          color: 'var(--text-tertiary)', marginTop: '4px', display: 'block',
        }}>Minimum 10 picks per bucket required</span>
      )}
    </div>
  );
}


function RiskProfile({ risk }) {
  return (
    <>
      <SectionLabel>Risk Profile</SectionLabel>
      <div style={{
        backgroundColor: 'var(--surface-1)', borderRadius: '20px',
        border: '1px solid var(--stroke-subtle)', padding: '20px',
        marginBottom: '16px',
      }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
          <RiskRow label="Max Drawdown" value={`-${risk.max_drawdown_pct || 0}%`} tooltip="This shows the largest historical drop from peak equity. Every profitable system has drawdowns. The question is whether they are within expectation." />
          <RiskRow label="Avg Days Between Picks" value={risk.avg_days_between_picks || '—'} />
          <RiskRow label="Avg Line Movement" value={`${risk.avg_line_move_against || 0} pts`} />
          <RiskRow label="Avg Edge Published" value={`${risk.avg_edge_published || 0}%`} tooltip="Higher average edge means fewer but stronger plays. Conviction scales with risk." />
        </div>
      </div>
    </>
  );
}

function RiskRow({ label, value, tooltip }) {
  return (
    <div style={{
      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
      paddingBottom: '12px', borderBottom: '1px solid var(--stroke-subtle)',
    }}>
      <span style={{
        fontSize: '13px', color: 'var(--text-secondary)',
        display: 'inline-flex', alignItems: 'center',
      }}>
        {label}
        {tooltip && <InfoTooltip text={tooltip} />}
      </span>
      <span style={{
        fontFamily: 'var(--font-mono)', fontSize: '14px',
        color: 'var(--text-primary)', fontWeight: 600,
      }}>{value}</span>
    </div>
  );
}


function DisciplineScore({ discipline }) {
  return (
    <>
      <SectionLabel>Discipline Score</SectionLabel>
      <InfoCallout
        header="Passing Is a Position"
        text="Volume increases variance. Filtration preserves capital. Edge only matters when it exceeds risk."
      />
      <div style={{
        backgroundColor: 'var(--surface-1)', borderRadius: '20px',
        border: '1px solid var(--stroke-subtle)', padding: '24px',
        marginBottom: '16px',
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'baseline', gap: '12px', marginBottom: '4px' }}>
              <span style={{
                fontSize: '13px', color: 'var(--text-secondary)',
              }}>Selectivity Rate</span>
              <span style={{
                fontFamily: 'var(--font-mono)', fontSize: '22px',
                color: 'var(--text-primary)', fontWeight: 700,
              }}>{discipline.selectivity_rate || 0}%</span>
            </div>
            <div style={{
              fontSize: '12px', color: 'var(--text-tertiary)',
            }}>Industry Avg: {discipline.industry_avg || 78}%</div>
          </div>
          <div style={{
            width: '56px', height: '56px', borderRadius: '14px',
            background: discipline.restraint_grade?.startsWith('A')
              ? 'linear-gradient(135deg, rgba(52,211,153,0.15), rgba(52,211,153,0.05))'
              : 'linear-gradient(135deg, rgba(255,255,255,0.08), rgba(255,255,255,0.02))',
            border: discipline.restraint_grade?.startsWith('A')
              ? '1px solid rgba(52,211,153,0.3)'
              : '1px solid var(--stroke-subtle)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <span style={{
              fontFamily: 'var(--font-mono)', fontSize: '20px', fontWeight: 800,
              color: discipline.restraint_grade?.startsWith('A') ? 'var(--green-profit)' : 'var(--text-primary)',
            }}>{discipline.restraint_grade || '—'}</span>
          </div>
        </div>

        <SelectivityBar selectivity={discipline.selectivity_rate || 0} industryAvg={discipline.industry_avg || 78} />

        <div style={{
          marginTop: '16px', paddingTop: '14px',
          borderTop: '1px solid var(--stroke-subtle)',
        }}>
          <p style={{
            fontSize: '13px', color: 'var(--text-secondary)', lineHeight: '1.6',
          }}>
            Capital preserved: <span style={{
              fontFamily: 'var(--font-mono)', fontWeight: 700,
              color: 'var(--green-profit)',
            }}>+${(discipline.capital_preserved || 0).toLocaleString()}</span> from avoided -EV spots
          </p>
        </div>
      </div>
    </>
  );
}


function LatestResultCard({ picks }) {
  if (!picks || picks.length === 0) return null;
  const latest = picks[0];
  if (!latest || (latest.result !== 'win' && latest.result !== 'loss' && latest.result !== 'push')) return null;

  const isWin = latest.result === 'win';
  const isPush = latest.result === 'push';
  const accentColor = isPush ? 'var(--text-secondary)' : isWin ? 'var(--green-profit)' : 'var(--red-loss)';
  const accentBg = isPush ? 'rgba(255,255,255,0.04)' : isWin ? 'rgba(52,211,153,0.06)' : 'rgba(239,68,68,0.06)';
  const accentBorder = isPush ? 'rgba(255,255,255,0.1)' : isWin ? 'rgba(52,211,153,0.18)' : 'rgba(239,68,68,0.18)';
  const resultLabel = isPush ? 'Push' : isWin ? 'Win' : 'Loss';
  const profitDisplay = latest.profit_units != null
    ? `${latest.profit_units >= 0 ? '+' : ''}${latest.profit_units}u`
    : isPush ? '0u' : isWin ? '+0.91u' : '-1.0u';

  return (
    <>
      <SectionLabel>Latest Result</SectionLabel>
      <div style={{
        backgroundColor: accentBg,
        borderRadius: '20px',
        border: `1px solid ${accentBorder}`,
        padding: '20px 24px',
        marginBottom: '16px',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <div style={{
            width: '40px', height: '40px', borderRadius: '50%',
            backgroundColor: isPush ? 'rgba(255,255,255,0.05)' : isWin ? 'rgba(52,211,153,0.12)' : 'rgba(239,68,68,0.12)',
            border: `2px solid ${accentColor}`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            flexShrink: 0,
          }}>
            {isPush ? (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={accentColor} strokeWidth="2.5" strokeLinecap="round">
                <line x1="6" y1="12" x2="18" y2="12"/>
              </svg>
            ) : isWin ? (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={accentColor} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="20 6 9 17 4 12"/>
              </svg>
            ) : (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={accentColor} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <line x1="18" y1="6" x2="6" y2="18"/>
                <line x1="6" y1="6" x2="18" y2="18"/>
              </svg>
            )}
          </div>
          <div style={{ flex: 1 }}>
            <div style={{
              fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 600,
              letterSpacing: '1.5px', textTransform: 'uppercase',
              color: accentColor, marginBottom: '3px',
            }}>{resultLabel}</div>
            <div style={{
              fontFamily: 'var(--font-sans)', fontSize: '15px', fontWeight: 600,
              color: 'var(--text-primary)',
            }}>
              {latest.side} {latest.line > 0 ? `+${latest.line}` : latest.line}
            </div>
            {(latest.away_team || latest.home_team) && (
              <div style={{
                fontFamily: 'var(--font-mono)', fontSize: '11px',
                color: 'var(--text-secondary)', marginTop: '2px',
              }}>
                {latest.away_team} @ {latest.home_team}
              </div>
            )}
          </div>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '20px', fontWeight: 700,
            color: accentColor,
          }}>
            {profitDisplay}
          </div>
        </div>
      </div>
    </>
  );
}

function RecentPickLog({ picks }) {
  if (!picks || picks.length === 0) return null;

  return (
    <>
      <SectionLabel>Recent Picks</SectionLabel>
      <div style={{
        backgroundColor: 'var(--surface-1)', borderRadius: '20px',
        border: '1px solid var(--stroke-subtle)',
        marginBottom: '16px', overflow: 'hidden',
      }}>
        {picks.map((pick, i) => (
          <PickLogRow key={pick.id} pick={pick} isLast={i === picks.length - 1} />
        ))}
      </div>
    </>
  );
}

function toET(isoStr) {
  try {
    const d = new Date(isoStr);
    if (isNaN(d.getTime())) return null;
    return new Date(d.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  } catch { return null; }
}

function formatPickTimestamp(gameDate, startTime, publishedAt) {
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

  let gamePart = '';
  if (startTime && startTime.includes('T')) {
    const et = toET(startTime);
    if (et) {
      let hours = et.getHours();
      const mins = et.getMinutes().toString().padStart(2, '0');
      const ampm = hours >= 12 ? 'PM' : 'AM';
      hours = hours % 12 || 12;
      gamePart = `${months[et.getMonth()]} ${et.getDate()} · ${hours}:${mins} ${ampm} ET`;
    }
  }
  if (!gamePart && gameDate && typeof gameDate === 'string' && gameDate.match(/^\d{4}-\d{2}-\d{2}/)) {
    const [y, m, day] = gameDate.split('-');
    gamePart = `${months[parseInt(m)-1]} ${parseInt(day)}`;
  }

  let postedPart = '';
  if (publishedAt) {
    const et = toET(publishedAt);
    if (et) {
      let hours = et.getHours();
      const mins = et.getMinutes().toString().padStart(2, '0');
      const ampm = hours >= 12 ? 'PM' : 'AM';
      hours = hours % 12 || 12;
      postedPart = `Posted ${hours}:${mins} ${ampm} ET`;
    }
  }
  if (gamePart && postedPart) return `${gamePart} · ${postedPart}`;
  if (gamePart) return gamePart;
  if (postedPart) return postedPart;
  return null;
}

function PickLogRow({ pick, isLast }) {
  const isWin = pick.result === 'win';
  const isLoss = pick.result === 'loss';
  const isPending = pick.result === 'pending';
  const timestamp = formatPickTimestamp(pick.game_date, pick.start_time, pick.published_at);

  return (
    <div style={{
      padding: '16px 20px',
      borderBottom: isLast ? 'none' : '1px solid var(--stroke-subtle)',
    }}>
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        marginBottom: '4px',
      }}>
        <span style={{
          fontFamily: 'var(--font-sans)', fontSize: '14px',
          color: 'var(--text-primary)', fontWeight: 600,
        }}>{pick.side}</span>
        <span style={{
          fontFamily: 'var(--font-mono)', fontSize: '12px', fontWeight: 700,
          color: isWin ? 'var(--green-profit)' : isLoss ? 'var(--red-loss)' : 'var(--gold-pro)',
          backgroundColor: isWin ? 'rgba(52,211,153,0.1)' : isLoss ? 'rgba(239,68,68,0.1)' : 'rgba(245,158,11,0.1)',
          padding: '3px 8px', borderRadius: '4px',
        }}>
          {isWin ? 'WIN' : isLoss ? 'LOSS' : 'PENDING'}
        </span>
      </div>
      {(pick.away_team || pick.home_team) && (
        <div style={{
          fontFamily: 'var(--font-mono)', fontSize: '11px',
          color: 'var(--text-secondary)', marginBottom: '4px',
        }}>
          {pick.away_team} @ {pick.home_team}
        </div>
      )}
      {timestamp && (
        <div style={{
          fontFamily: 'var(--font-mono)', fontSize: '10px',
          color: 'var(--text-tertiary)', marginBottom: '8px',
        }}>
          {timestamp}
        </div>
      )}
      <div style={{
        display: 'flex', gap: '10px', flexWrap: 'wrap',
      }}>
        <PickMeta label="Edge" value={`${pick.edge_pct || 0}%`} />
        {pick.predicted_margin !== null && pick.predicted_margin !== undefined && (
          <PickMeta label="Margin" value={`${pick.predicted_margin > 0 ? '+' : ''}${pick.predicted_margin}`} />
        )}
        {pick.cover_prob !== null && pick.cover_prob !== undefined && (
          <PickMeta label="Cover" value={`${(pick.cover_prob * 100).toFixed(0)}%`} />
        )}
        {pick.closing_spread !== null && pick.closing_spread !== undefined && (
          <PickMeta label="Close" value={pick.closing_spread > 0 ? `+${pick.closing_spread}` : pick.closing_spread} />
        )}
        {pick.line_movement !== null && pick.line_movement !== undefined && pick.line_movement !== 0 && (
          <PickMeta label="Move" value={`${pick.line_movement > 0 ? '+' : ''}${pick.line_movement}`}
            color={Math.abs(pick.line_movement) > 1 ? 'var(--gold-pro)' : undefined} />
        )}
      </div>
    </div>
  );
}

function PickMeta({ label, value, color }) {
  return (
