          }}>14 Days Free</h2>
          <p style={{
            color: 'var(--text-secondary)', fontSize: '14px', textAlign: 'center',
            margin: '0 0 24px', lineHeight: '1.5',
          }}>Full access to all picks and features. No credit card required.</p>

          <form onSubmit={handleStart}>
            <div style={{ marginBottom: '12px' }}>
              <label style={{
                display: 'block', fontSize: '12px', fontWeight: 600,
                color: 'var(--text-tertiary)', marginBottom: '6px',
                textTransform: 'uppercase', letterSpacing: '0.5px',
              }}>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                placeholder="you@example.com"
                style={{
                  width: '100%', padding: '12px 14px', fontSize: '15px',
                  backgroundColor: 'var(--surface-2)', border: '1px solid var(--stroke-subtle)',
                  borderRadius: '10px', color: 'var(--text-primary)',
                  outline: 'none', boxSizing: 'border-box',
                  fontFamily: 'var(--font-sans)',
                }}
              />
            </div>
            <div style={{ marginBottom: '16px' }}>
              <label style={{
                display: 'block', fontSize: '12px', fontWeight: 600,
                color: 'var(--text-tertiary)', marginBottom: '6px',
                textTransform: 'uppercase', letterSpacing: '0.5px',
              }}>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                minLength={6}
                placeholder="6+ characters"
                style={{
                  width: '100%', padding: '12px 14px', fontSize: '15px',
                  backgroundColor: 'var(--surface-2)', border: '1px solid var(--stroke-subtle)',
                  borderRadius: '10px', color: 'var(--text-primary)',
                  outline: 'none', boxSizing: 'border-box',
                  fontFamily: 'var(--font-sans)',
                }}
              />
            </div>

            {error && (
              <p style={{
                color: '#ef4444', fontSize: '13px', margin: '0 0 12px',
                padding: '10px 12px', backgroundColor: 'rgba(239,68,68,0.08)',
                borderRadius: '8px',
              }}>{error}</p>
            )}

            <button type="submit" disabled={loading} style={{
              width: '100%', padding: '14px', fontSize: '15px', fontWeight: 700,
              backgroundColor: 'var(--blue-primary)', border: 'none',
              borderRadius: '10px', color: '#fff', cursor: 'pointer',
              fontFamily: 'var(--font-sans)', opacity: loading ? 0.6 : 1,
            }}>
              {loading ? 'Starting trial...' : 'Start Free Trial'}
            </button>
          </form>

          <div style={{
            marginTop: '20px', padding: '14px', backgroundColor: 'var(--surface-2)',
            borderRadius: '10px',
          }}>
            <p style={{
              fontSize: '12px', color: 'var(--text-tertiary)', margin: 0,
              textAlign: 'center', lineHeight: '1.6',
            }}>
              After 14 days, subscribe at $29/mo or $99/yr (founding rate). Cancel anytime. No auto-charge.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

function useCardAnimations() {
  const injected = useRef(false);
  useEffect(() => {
    if (injected.current) return;
    injected.current = true;
    const style = document.createElement('style');
    style.textContent = `
      @keyframes spBorderShimmer {
        0% { background-position: 0% 50%; }
        50% { background-position: 100% 50%; }
        100% { background-position: 0% 50%; }
      }
      @keyframes spGoldRing {
        0% { background-position: 0% 50%; }
        50% { background-position: 100% 50%; }
        100% { background-position: 0% 50%; }
      }
    `;
    document.head.appendChild(style);
  }, []);
}

function MembershipCard({ user, isPro }) {
  useCardAnimations();
  const isFounder = user.founding_member;
  const initial = (user.display_name || user.username || user.email || '?')[0].toUpperCase();
  const displayName = user.display_name || user.username || user.email?.split('@')[0] || '';
  const memberSince = user.created_at
    ? new Date(user.created_at).toLocaleDateString('en-US', { month: 'short', year: '2-digit' })
    : '';

  const planLabel = user.subscription_status === 'trial'
    ? '14-Day Trial'
    : isFounder
      ? 'Lifetime'
      : user.subscription_plan
        ? user.subscription_plan.charAt(0).toUpperCase() + user.subscription_plan.slice(1)
        : user.subscription_status || 'Free';

  const borderBg = isFounder
    ? 'linear-gradient(135deg, rgba(245,166,35,0.6) 0%, rgba(255,215,0,0.3) 25%, rgba(184,134,11,0.5) 50%, rgba(255,215,0,0.3) 75%, rgba(245,166,35,0.6) 100%)'
    : isPro
      ? 'linear-gradient(135deg, rgba(79,134,247,0.5) 0%, rgba(47,95,214,0.3) 50%, rgba(79,134,247,0.5) 100%)'
      : 'var(--stroke-subtle)';

  const ringBg = isFounder
    ? 'linear-gradient(135deg, #F5A623, #FFD700, #B8860B, #FFD700, #F5A623)'
    : isPro
      ? 'linear-gradient(135deg, #4F86F7, #6B8BF5, #2F5FD6)'
      : 'var(--stroke-muted)';

  const crestColor = isFounder ? 'rgba(245,166,35,0.06)' : 'rgba(255,255,255,0.03)';

  return (
    <div style={{
      borderRadius: '20px',
      padding: '1.5px',
      background: borderBg,
      backgroundSize: '200% 200%',
      animation: isFounder || isPro ? 'spBorderShimmer 6s ease infinite' : 'none',
      marginBottom: '16px',
    }}>
      <div style={{
        position: 'relative',
        borderRadius: '19px',
        padding: '24px 22px 20px',
        backgroundColor: 'var(--surface-1)',
        overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', inset: 0, pointerEvents: 'none', borderRadius: '19px',
          backgroundImage: 'url("data:image/svg+xml,%3Csvg viewBox=\'0 0 256 256\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\' opacity=\'0.04\'/%3E%3C/svg%3E")',
        }} />

        <svg viewBox="0 0 40 40" width="180" height="180" fill="none" style={{
          position: 'absolute', right: '-20px', top: '-20px',
          opacity: 0.8, pointerEvents: 'none',
        }}>
          <path d="M20 4L6 10v10c0 9.2 6 17.4 14 20 8-2.6 14-10.8 14-20V10L20 4z" stroke={crestColor} strokeWidth="1.5" fill="none"/>
          <rect x="12" y="24" width="3" height="6" rx="1" fill={isFounder ? 'rgba(245,166,35,0.03)' : 'rgba(255,255,255,0.02)'}/>
          <rect x="17" y="20" width="3" height="10" rx="1" fill={isFounder ? 'rgba(245,166,35,0.03)' : 'rgba(255,255,255,0.02)'}/>
          <rect x="22" y="22" width="3" height="8" rx="1" fill={isFounder ? 'rgba(245,166,35,0.03)' : 'rgba(255,255,255,0.02)'}/>
          <path d="M11 22L17 16L22 19L30 11" stroke={crestColor} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          <path d="M26 11h4v4" stroke={crestColor} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>

        <div style={{ display: 'flex', alignItems: 'center', gap: '14px', marginBottom: '20px', position: 'relative', zIndex: 1 }}>
          <div style={{
            width: '52px', height: '52px', borderRadius: '16px',
            display: 'grid', placeItems: 'center',
            position: 'relative',
          }}>
            <div style={{
              position: 'absolute', inset: '-3px', borderRadius: '19px',
              background: ringBg,
              backgroundSize: '300% 300%',
              animation: isFounder ? 'spGoldRing 4s ease infinite' : 'none',
              zIndex: 0,
            }} />
            <div style={{
              position: 'relative', width: '100%', height: '100%', borderRadius: '15px',
              background: 'linear-gradient(135deg, #4F86F7, #2F5FD6)',
              display: 'grid', placeItems: 'center',
              fontFamily: 'var(--font-serif)', fontSize: '22px',
              fontWeight: 700, color: 'var(--bg)',
              zIndex: 1,
            }}>
              {initial}
            </div>
          </div>

          <div style={{ flex: 1 }}>
            <div style={{
              display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '3px',
            }}>
              <span style={{
                fontFamily: 'var(--font-serif)', fontSize: '20px',
                fontWeight: 700, color: 'var(--text-primary)',
              }}>{displayName}</span>
              {isPro && (
                <div style={{
                  width: '20px', height: '20px', borderRadius: '50%',
                  background: 'var(--green, #34D399)',
                  display: 'grid', placeItems: 'center', flexShrink: 0,
                }}>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="var(--bg, #0A0D14)" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M20 6L9 17l-5-5"/>
                  </svg>
                </div>
              )}
            </div>
            <div style={{
              fontFamily: 'var(--font-mono)', fontSize: '11px',
              color: 'var(--text-tertiary)', fontWeight: 400,
            }}>{user.email}</div>
          </div>
        </div>

        {isFounder && (
          <div style={{
            display: 'flex', alignItems: 'center', justifyContent: 'space-between',
            marginBottom: '16px', position: 'relative', zIndex: 1,
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '28px', height: '28px', display: 'grid', placeItems: 'center' }}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="#F5A623" style={{ filter: 'drop-shadow(0 0 6px rgba(245,166,35,0.4))' }}>
                  <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/>
                </svg>
              </div>
              <span style={{
                fontFamily: 'var(--font-mono)', fontSize: '10px',
                fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase',
                background: 'linear-gradient(135deg, #FFD700, #F5A623, #B8860B)',
                WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
                backgroundClip: 'text',
              }}>Founding Member</span>
            </div>
            <span style={{
              fontFamily: 'var(--font-mono)', fontSize: '32px',
              fontWeight: 800, lineHeight: 1,
              background: 'linear-gradient(135deg, #FFD700, #F5A623)',
              WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
              backgroundClip: 'text',
              filter: 'drop-shadow(0 0 8px rgba(245,166,35,0.2))',
            }}>
              #{String(user.founding_number || '').padStart(3, '0')}
            </span>
          </div>
        )}

        <div style={{
          borderTop: `1px solid ${isFounder ? 'rgba(245,166,35,0.1)' : 'var(--stroke-subtle)'}`,
          paddingTop: '16px',
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          position: 'relative', zIndex: 1,
        }}>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '10px',
            fontWeight: 700, letterSpacing: '1.5px', textTransform: 'uppercase',
            padding: '5px 14px', borderRadius: '6px',
            background: isPro
              ? 'linear-gradient(135deg, rgba(79,134,247,0.2), rgba(47,95,214,0.15))'
              : 'rgba(255,255,255,0.05)',
            color: isPro ? 'var(--blue-primary)' : 'var(--text-tertiary)',
            border: `1px solid ${isPro ? 'rgba(79,134,247,0.2)' : 'var(--stroke-subtle)'}`,
          }}>{planLabel}</div>

          {memberSince && (
            <span style={{
              fontFamily: 'var(--font-mono)', fontSize: '10px',
              color: 'var(--text-tertiary)', fontWeight: 500,
            }}>Since {memberSince}</span>
          )}

          {user.trial_end_date && user.subscription_status === 'trial' && (
            <span style={{
              fontFamily: 'var(--font-mono)', fontSize: '10px',
              color: 'var(--text-tertiary)',
            }}>
              Ends {new Date(user.trial_end_date).toLocaleDateString()}
            </span>
          )}
        </div>
      </div>
    </div>
  );
}

function StatRibbon() {
  const [stats, setStats] = useState(null);
  useEffect(() => {
    apiGet('/bets/stats').then(d => { if (d && !d.error) setStats(d); }).catch(() => {});
  }, []);

  const followed = stats?.adherence?.picks_followed ?? stats?.totalBets ?? 0;
  const discipline = stats?.winRate != null ? stats.winRate + '%' : '—';
  const profit = stats?.totalProfit != null ? (stats.totalProfit >= 0 ? '+' : '') + '$' + Math.abs(stats.totalProfit).toLocaleString() : '—';
  const profitPositive = stats?.totalProfit != null && stats.totalProfit >= 0;

  const items = [
    { value: followed, label: 'Followed', green: false },
    { value: discipline, label: 'Discipline', green: false },
    { value: profit, label: 'Tracked', green: profitPositive },
  ];

  return (
    <div style={{
      display: 'flex', gap: '1px',
      background: 'var(--stroke-subtle)',
      borderRadius: '14px', overflow: 'hidden',
      marginBottom: '20px',
    }}>
      {items.map((item, i) => (
        <div key={i} style={{
          flex: 1, background: 'var(--surface-1)',
          padding: '14px 8px', textAlign: 'center',
          borderRadius: i === 0 ? '14px 0 0 14px' : i === 2 ? '0 14px 14px 0' : '0',
        }}>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '18px',
            fontWeight: 800, lineHeight: 1, marginBottom: '4px',
            color: item.green ? 'var(--green, #34D399)' : 'var(--text-primary)',
          }}>{item.value}</div>
          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '8px',
            fontWeight: 600, letterSpacing: '1px', textTransform: 'uppercase',
            color: 'var(--text-tertiary)',
          }}>{item.label}</div>
        </div>
      ))}
    </div>
  );
}

src/App.css.content:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

.app {
  min-height: 100vh;
  background: linear-gradient(135deg, #0F172A 0%, #1E293B 100%);
  color: #fff;
}

header {
  background: rgba(15, 23, 42, 0.9);
  border-bottom: 1px solid rgba(59, 130, 246, 0.2);
  padding: 24px 0 0;
}

.header-content {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px 24px;
  text-align: center;
}

header h1 {
  font-size: 2.5rem;
  font-weight: 700;
  background: linear-gradient(135deg, #3B82F6, #6366F1);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

header p {
  color: #94A3B8;
  margin-top: 8px;
}

.trust-banner {
  display: flex;
  justify-content: center;
  gap: 24px;
  padding: 16px 24px;
  background: rgba(59, 130, 246, 0.1);
  border-top: 1px solid rgba(59, 130, 246, 0.2);
  flex-wrap: wrap;
}

.trust-banner.loading {
  justify-content: center;
  color: #94A3B8;
}

.trust-item {
  display: flex;
  align-items: center;
  gap: 8px;
}

.trust-icon {
  font-size: 1.2rem;
}

.trust-content {
  display: flex;
  flex-direction: column;
}

.trust-label {
  font-size: 0.75rem;
  color: #94A3B8;
  text-transform: uppercase;
}

.trust-value {
  font-weight: 600;
  color: #fff;
}

.trust-divider {
  width: 1px;
  height: 32px;
  background: rgba(148, 163, 184, 0.3);
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 32px 24px;
}

.loading-state {
  text-align: center;
  padding: 48px;
  color: #94A3B8;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 24px;
  margin-bottom: 32px;
}

.stats-card {
  background: rgba(30, 41, 59, 0.8);
  border: 1px solid rgba(59, 130, 246, 0.2);
  border-radius: 12px;
  padding: 24px;
  display: flex;
  align-items: center;
  gap: 16px;
  transition: transform 0.2s, border-color 0.2s;
}

.stats-card:hover {
  transform: translateY(-2px);
  border-color: rgba(59, 130, 246, 0.4);
}

.stats-icon {
  width: 48px;
  height: 48px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
}

.stats-content {
  display: flex;
  flex-direction: column;
}

.stats-label {
  font-size: 0.875rem;
  color: #94A3B8;
}

.stats-value {
  font-size: 1.5rem;
  font-weight: 700;
  color: #fff;
}

.stats-subtext {
  font-size: 0.75rem;
  color: #64748B;
}

.charts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(400px, 1fr));
  gap: 24px;
  margin-bottom: 32px;
}

.card {
  background: rgba(30, 41, 59, 0.8);
  border: 1px solid rgba(59, 130, 246, 0.2);
  border-radius: 12px;
  padding: 24px;
}

.card h3 {
  margin-bottom: 16px;
  font-size: 1.125rem;
  color: #fff;
}

.spread-stats .spread-bars {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.spread-item {
  display: flex;
  align-items: center;
  gap: 12px;
}

.spread-label {
  width: 100px;
  font-size: 0.875rem;
  color: #94A3B8;
}

.spread-bar-container {
  flex: 1;
  height: 24px;
  background: rgba(15, 23, 42, 0.6);
  border-radius: 4px;
  overflow: hidden;
}

.spread-bar {
  height: 100%;
  border-radius: 4px;
  transition: width 0.5s ease;
}

.spread-bar.home {
  background: linear-gradient(90deg, #10B981, #34D399);
}

.spread-bar.away {
  background: linear-gradient(90deg, #3B82F6, #60A5FA);
}

.spread-bar.push {
  background: linear-gradient(90deg, #F59E0B, #FBBF24);
}

.spread-value {
  width: 60px;
  text-align: right;
  font-weight: 600;
  color: #fff;
}

.calibration-chart {
  background: rgba(30, 41, 59, 0.8);
  border: 1px solid rgba(59, 130, 246, 0.2);
  border-radius: 12px;
  padding: 24px;
}

.calibration-chart h3 {
  margin-bottom: 8px;
}

.calibration-status {
  color: #94A3B8;
  font-size: 0.875rem;
  margin-bottom: 16px;
}

.status-excellent { color: #10B981; font-weight: 600; }
.status-good { color: #3B82F6; font-weight: 600; }
.status-moderate { color: #F59E0B; font-weight: 600; }
.status-poor { color: #EF4444; font-weight: 600; }

.calibration-bars {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.calibration-row {
  display: flex;
  align-items: center;
  gap: 12px;
}

.bucket-label {
  width: 80px;
  font-size: 0.875rem;
  color: #94A3B8;
}

.bar-container {
  flex: 1;
  height: 20px;
  background: rgba(15, 23, 42, 0.6);
  border-radius: 4px;
  position: relative;
  overflow: hidden;
}

.bar {
  position: absolute;
  height: 100%;
  border-radius: 4px;
}

.bar.expected {
  background: rgba(148, 163, 184, 0.3);
  z-index: 1;
}

.bar.actual {
  z-index: 2;
}

.bar.actual.good {
  background: linear-gradient(90deg, #10B981, #34D399);
}

.bar.actual.off {
  background: linear-gradient(90deg, #F59E0B, #FBBF24);
}

.bar-values {
  width: 140px;
  font-size: 0.75rem;
  color: #94A3B8;
}

.calibration-legend {
  display: flex;
  gap: 24px;
  margin-top: 16px;
  padding-top: 16px;
  border-top: 1px solid rgba(148, 163, 184, 0.2);
}

.calibration-legend span {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.75rem;
  color: #94A3B8;
}

.legend-dot {
  width: 12px;
  height: 12px;
  border-radius: 2px;
}

.legend-dot.expected {
  background: rgba(148, 163, 184, 0.3);
}

.legend-dot.actual {
  background: linear-gradient(90deg, #10B981, #34D399);
}

.no-data {
  color: #64748B;
  font-style: italic;
  text-align: center;
  padding: 24px;
}

.system-health {
  background: rgba(30, 41, 59, 0.8);
  border: 1px solid rgba(59, 130, 246, 0.2);
  border-radius: 12px;
  padding: 24px;
}

.system-health h3 {
  margin-bottom: 16px;
}

.health-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
}

.health-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px;
  background: rgba(15, 23, 42, 0.6);
  border-radius: 8px;
}

.health-status-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
}

.health-item.operational .health-status-dot {
  background: #10B981;
  box-shadow: 0 0 8px rgba(16, 185, 129, 0.5);
}

.health-item.warning .health-status-dot {
  background: #F59E0B;
  box-shadow: 0 0 8px rgba(245, 158, 11, 0.5);
}

.health-item.error .health-status-dot {
  background: #EF4444;
  box-shadow: 0 0 8px rgba(239, 68, 68, 0.5);
}

.health-content {
  display: flex;
  flex-direction: column;
}

.health-name {
  font-weight: 600;
  color: #fff;
  font-size: 0.875rem;
}

.health-message {
  color: #64748B;
  font-size: 0.75rem;
}

footer {
  text-align: center;
  padding: 32px 24px;
  border-top: 1px solid rgba(59, 130, 246, 0.2);
  color: #64748B;
}

footer .disclaimer {
  font-size: 0.75rem;
  margin-top: 8px;
  color: #475569;
}

.spinner {
  width: 20px;
  height: 20px;
  border: 2px solid rgba(59, 130, 246, 0.3);
  border-top-color: #3B82F6;
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin-right: 8px;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* Today's Picks Section */
.picks-section {
  margin-bottom: 48px;
}

.picks-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
  flex-wrap: wrap;
  gap: 16px;
}

.picks-section h2 {
  font-size: 1.5rem;
  font-weight: 700;
}

.filter-buttons {
  display: flex;
  gap: 8px;
}

.filter-buttons button {
  padding: 8px 16px;
  border: 1px solid rgba(59, 130, 246, 0.3);
  border-radius: 8px;
  background: rgba(30, 41, 59, 0.8);
  color: #94A3B8;
  cursor: pointer;
  transition: all 0.2s;
}

.filter-buttons button:hover {
  border-color: rgba(59, 130, 246, 0.6);
  color: #fff;
}

.filter-buttons button.active {
  background: linear-gradient(135deg, #3B82F6, #6366F1);
  border-color: transparent;
  color: #fff;
}

.picks-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 20px;
}

.pick-card {
  background: rgba(30, 41, 59, 0.8);
  border: 1px solid rgba(59, 130, 246, 0.2);
  border-radius: 12px;
  padding: 20px;
  transition: transform 0.2s, border-color 0.2s;
}

.pick-card:hover {
  transform: translateY(-2px);
  border-color: rgba(59, 130, 246, 0.4);
}

.pick-card.very-high {
  border-left: 4px solid #10B981;
}

.pick-card.high {
  border-left: 4px solid #3B82F6;
}

.pick-card.medium {
  border-left: 4px solid #F59E0B;
}

.matchup {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 16px;
  font-size: 1.125rem;
}

.away-team, .home-team {
  font-weight: 600;
}

.at {
  color: #64748B;
  font-size: 0.875rem;
}

.prediction {
  background: rgba(15, 23, 42, 0.6);
  border-radius: 8px;
  padding: 12px;
  margin-bottom: 12px;
  text-align: center;
}

.pick-label {
  font-size: 0.75rem;
  color: #64748B;
  text-transform: uppercase;
}

.pick-value {
  font-size: 1.25rem;
  font-weight: 700;
  color: #10B981;
}

.spread {
  color: #94A3B8;
  font-size: 0.875rem;
}

.confidence-meter {
  margin-bottom: 12px;
}

.meter-label {
  font-size: 0.75rem;
  color: #64748B;
  margin-bottom: 4px;
}

.meter-bar {
  height: 8px;
  background: rgba(15, 23, 42, 0.6);
  border-radius: 4px;
  overflow: hidden;
  margin-bottom: 4px;
}

.meter-fill {
  height: 100%;
  background: linear-gradient(90deg, #3B82F6, #10B981);
  border-radius: 4px;
  transition: width 0.5s ease;
}

.meter-value {
  font-size: 0.875rem;
  font-weight: 600;
  color: #10B981;
}

.edge-info {
  display: flex;
  justify-content: space-between;
  font-size: 0.875rem;
  color: #94A3B8;
  padding-top: 8px;
  border-top: 1px solid rgba(148, 163, 184, 0.1);
}

.edge-value {
  color: #10B981;
  font-weight: 600;
}

.line-movement {
  margin-top: 8px;
  font-size: 0.75rem;
  padding: 4px 8px;
  border-radius: 4px;
  display: inline-block;
}

.line-movement.up {
  background: rgba(239, 68, 68, 0.2);
  color: #F87171;
}

.line-movement.down {
  background: rgba(16, 185, 129, 0.2);
  color: #34D399;
}

.line-movement.sharp {
  background: rgba(16, 185, 129, 0.2);
  color: #34D399;
  display: flex;
  align-items: center;
  gap: 6px;
}

.line-movement.public {
  background: rgba(239, 68, 68, 0.15);
  color: #F87171;
  display: flex;
  align-items: center;
  gap: 6px;
}

.movement-icon {
  font-size: 1rem;
}

.movement-text {
  font-size: 0.75rem;
}

.line-open-close {
  margin-top: 8px;
  font-size: 0.75rem;
  color: #64748B;
  display: flex;
  align-items: center;
  gap: 4px;
}

.oc-label {
  color: #94A3B8;
}

.oc-arrow {
  color: #3B82F6;
  margin: 0 4px;
}

.closing-line-stats {
  padding: 12px 0;
}

.clv-main {
  text-align: center;
  margin-bottom: 16px;
  padding: 16px;
  background: rgba(16, 185, 129, 0.1);
  border-radius: 8px;
  border: 1px solid rgba(16, 185, 129, 0.2);
}

.clv-rate {
  display: block;
  font-size: 2rem;
  font-weight: 700;
  color: #10B981;
}

.clv-label {
  font-size: 0.875rem;
  color: #94A3B8;
}

.clv-note {
  margin-top: 12px;
  font-size: 0.75rem;
  color: #64748B;
  font-style: italic;
  text-align: center;
}

.no-picks {
  text-align: center;
  padding: 48px;
  background: rgba(30, 41, 59, 0.8);
  border: 1px solid rgba(59, 130, 246, 0.2);
  border-radius: 12px;
}

.no-picks p {
  color: #94A3B8;
}

.no-picks .hint {
  margin-top: 8px;
  font-size: 0.875rem;
  color: #64748B;
}

/* Locked Picks */
.pick-card.locked {
  position: relative;
  overflow: hidden;
}

.pick-card.locked .matchup {
  filter: blur(2px);
}

.locked-overlay {
  position: absolute;
  inset: 0;
  background: rgba(15, 23, 42, 0.85);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  backdrop-filter: blur(4px);
}

.lock-icon {
  font-size: 2rem;
}

.lock-text {
  color: #94A3B8;
  font-size: 0.875rem;
}

.unlock-btn {
  background: linear-gradient(135deg, #F59E0B, #EA580C);
  color: white;
  border: none;
  padding: 10px 20px;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.2s, box-shadow 0.2s;
}

.unlock-btn:hover {
  transform: scale(1.05);
  box-shadow: 0 4px 20px rgba(245, 158, 11, 0.3);
}

/* Game Time Countdown */
.game-time {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 0.875rem;
  color: #FBBF24;
  margin-bottom: 12px;
}

/* Win Streak Badge */
.streak-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  background: linear-gradient(135deg, #EA580C, #DC2626);
  color: white;
  padding: 4px 12px;
  border-radius: 9999px;
  font-size: 0.75rem;
  font-weight: 600;
}

/* ROI Tip Box */
.roi-tip {
  background: rgba(30, 58, 138, 0.3);
  border-radius: 12px;
  padding: 16px;
  margin-bottom: 16px;
  border: 1px solid rgba(59, 130, 246, 0.2);
}

.roi-tip-text {
  color: #93C5FD;
  font-size: 0.875rem;
  line-height: 1.5;
}

/* Active Members */
.active-members {
  color: #64748B;
  font-size: 0.75rem;
  text-align: center;
  margin-top: 8px;
}

/* Mobile Upgrade Bar */
.mobile-upgrade-bar {
  display: none;
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 16px;
  padding-bottom: max(16px, env(safe-area-inset-bottom));
  background: linear-gradient(135deg, #F59E0B, #EA580C);
  z-index: 100;
}

.mobile-upgrade-bar button {
  width: 100%;
  background: white;
  color: #EA580C;
  border: none;
  padding: 14px 24px;
  border-radius: 10px;
  font-weight: 700;
  font-size: 1rem;
  cursor: pointer;
}

@media (max-width: 768px) {
  .mobile-upgrade-bar {
    display: block;
  }

  .picks-section {
    padding-bottom: 80px;
  }
}

.loading {
  text-align: center;
  padding: 48px;
  color: #94A3B8;
}

/* Model Transparency Section */
.transparency-section {
  margin-bottom: 48px;
}

.transparency-section h2 {
  font-size: 1.5rem;
  font-weight: 700;
  margin-bottom: 8px;
}

.section-subtitle {
  color: #94A3B8;
  margin-bottom: 24px;
}

.transparency-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(400px, 1fr));
  gap: 24px;
}

.transparency-card {
  background: rgba(30, 41, 59, 0.8);
  border: 1px solid rgba(59, 130, 246, 0.2);
  border-radius: 12px;
  padding: 24px;
}

.transparency-card.full-width {
  grid-column: 1 / -1;
}

.transparency-card h3 {
  font-size: 1.125rem;
  margin-bottom: 8px;
}

.card-description {
  font-size: 0.875rem;
  color: #64748B;
  margin-bottom: 16px;
}

.calibration-table {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.table-header, .table-row {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr 1fr 1fr;
  gap: 8px;
  padding: 8px;
  font-size: 0.875rem;
}

.table-header {
  color: #64748B;
  border-bottom: 1px solid rgba(148, 163, 184, 0.2);
  font-weight: 600;
}

.table-row {
  background: rgba(15, 23, 42, 0.4);
  border-radius: 4px;
}

.bucket-name {
  font-weight: 600;
}

.highlight {
  color: #10B981;
  font-weight: 600;
}

.status.calibrated {
  color: #10B981;
}

.status.off {
  color: #F59E0B;
}

.status.pending {
  color: #64748B;
}

.calibration-summary {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 16px;
  padding-top: 16px;
  border-top: 1px solid rgba(148, 163, 184, 0.2);
}

.status-badge {
  padding: 4px 12px;
  border-radius: 12px;
  font-size: 0.75rem;
  font-weight: 600;
}

.status-badge.excellent {
  background: rgba(16, 185, 129, 0.2);
  color: #10B981;
}

.status-badge.good {
  background: rgba(59, 130, 246, 0.2);
  color: #3B82F6;
}

.status-badge.moderate {
  background: rgba(245, 158, 11, 0.2);
  color: #F59E0B;
}

.status-badge.poor {
  background: rgba(239, 68, 68, 0.2);
  color: #EF4444;
}

.performance-stats {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.stat-row {
  display: flex;
  justify-content: space-between;
  padding: 12px;
  background: rgba(15, 23, 42, 0.4);
  border-radius: 8px;
}

.stat-row .value {
  font-weight: 600;
}

.stat-row .value.success {
  color: #10B981;
}

.stat-row .value.error {
  color: #EF4444;
}

.stat-row .value.highlight {
  color: #3B82F6;
}

.methodology-content {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
}

.method-item {
  padding: 16px;
  background: rgba(15, 23, 42, 0.4);
  border-radius: 8px;
}

.method-item h4 {
  color: #3B82F6;
  font-size: 0.875rem;
  margin-bottom: 8px;
}

.method-item p {
  font-size: 0.875rem;
  color: #94A3B8;
  line-height: 1.5;
}

@media (max-width: 768px) {
  .trust-banner {
    gap: 12px;
  }

  .trust-divider {
    display: none;
  }

  .charts-grid,
  .transparency-grid {
    grid-template-columns: 1fr;
  }

  .picks-grid {
    grid-template-columns: 1fr;
  }

  .table-header, .table-row {
    grid-template-columns: 1fr 1fr 1fr;
    font-size: 0.75rem;
  }

  .table-header span:nth-child(4),
  .table-header span:nth-child(5),
  .table-row span:nth-child(4),
  .table-row span:nth-child(5) {
    display: none;
  }

  header h1 {
    font-size: 1.75rem;
  }
}

