            }}>
              <div style={{
                fontFamily: 'var(--font-mono)', fontSize: '28px', fontWeight: 800,
                color: 'var(--green-profit)', letterSpacing: '-0.5px',
              }}>{pick.edge_pct != null ? `+${pick.edge_pct}%` : '--'}</div>
