            borderRadius: '50%',
          }} />
          <ShieldLogo size={80} />
        </div>

        <h1 style={{
          fontFamily: 'var(--font-serif)',
          fontSize: '32px', fontWeight: 700,
          lineHeight: '1.15',
          color: 'var(--text-primary)',
          marginBottom: '12px',
        }}>
          One Pick Beats Five
        </h1>

        <p style={{
          fontFamily: 'var(--font-serif)',
          fontSize: '16px', fontWeight: 400,
          fontStyle: 'italic',
          color: 'var(--text-secondary)',
          marginBottom: '32px',
        }}>
          Discipline is the product.
        </p>

        <button
          onClick={() => { setAuthMode('register'); setShowAuth(true); }}
          style={{
            width: '100%', maxWidth: '240px',
            height: '52px', borderRadius: '14px',
            border: 'none',
            background: 'linear-gradient(135deg, var(--blue-primary), var(--blue-deep))',
            color: 'white',
            fontFamily: 'var(--font-sans)',
            fontSize: '16px', fontWeight: 700,
            cursor: 'pointer',
            marginBottom: '40px',
          }}
        >
          Start Free
        </button>
        <p style={{
          fontFamily: 'var(--font-sans)',
          fontSize: '12px', fontWeight: 500,
          color: 'var(--text-tertiary)',
          marginTop: '-28px', marginBottom: '28px',
        }}>
          14-day trial — no card required
        </p>

        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          gap: '16px', marginBottom: '16px',
          backgroundColor: 'var(--surface-1)',
          border: '1px solid var(--stroke-subtle)',
          borderRadius: '12px',
          padding: '14px 16px',
        }}>
          <span style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 500, letterSpacing: '0.5px', color: 'var(--text-tertiary)' }}>Active since Jan 2026</span>
          <ProofDot />
          <span style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 500, letterSpacing: '0.5px', color: 'var(--text-tertiary)' }}>All picks public</span>
          <ProofDot />
          <span style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 500, letterSpacing: '0.5px', color: 'var(--text-tertiary)' }}>0 deleted</span>
        </div>
      </div>

      <div style={{ padding: '0 28px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
        <ValueProp
          title="No edge, no pick"
          desc="We publish only when the model identifies sufficient value. Quiet days are intentional."
        />
        <ValueProp
          title="Process over outcomes"
          desc={`All picks tracked publicly. No deletes. No hindsight editing.${stats ? ` ${stats.total_picks} picks · ${stats.total_passes} passes to date` : ''}`}
        />
        <ValueProp
          title="Selectivity beats volume"
          desc={`Most bettors lose by betting too much.${stats ? ` Our ${stats.selectivity}% selectivity rate is the edge.` : ' Selectivity is the edge.'}`}
        />
      </div>

      {stats && (
        <div style={{ padding: '16px 28px 0' }}>
          <div style={{
            backgroundColor: 'var(--surface-1)',
            borderRadius: '16px',
            border: '1px solid var(--stroke-subtle)',
            padding: '20px',
          }}>
            <div style={{
              fontSize: '11px', fontWeight: 600, color: 'var(--text-tertiary)',
              textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: '16px',
            }}>Live Performance</div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '12px' }}>
              <LandingStat label="Record" value={stats.record || '0-0'} />
              <LandingStat label="Win Rate" value={`${stats.win_rate || 0}%`} />
              <LandingStat
                label="P&L"
                value={`${stats.pnl >= 0 ? '+' : ''}${stats.pnl || 0}u`}
                color={stats.pnl >= 0 ? 'var(--green-profit)' : 'var(--red-loss)'}
              />
            </div>
          </div>
        </div>
      )}

      {spotsLeft !== null && spotsLeft > 0 && (
        <div style={{ padding: '16px 28px 0' }}>
          <div style={{
            backgroundColor: 'rgba(79, 134, 247, 0.06)',
            borderRadius: '16px',
            border: '1px solid rgba(79, 134, 247, 0.15)',
            padding: '20px',
            textAlign: 'center',
          }}>
            <div style={{
              fontFamily: 'var(--font-sans)',
              fontSize: '16px', fontWeight: 700,
              color: 'var(--text-primary)', marginBottom: '6px',
            }}>Founding member pricing</div>
            <p style={{ fontSize: '14px', color: 'var(--text-secondary)', marginBottom: '4px' }}>
              First 500 lock in <span style={{ fontFamily: 'var(--font-mono)', color: 'var(--text-primary)', fontWeight: 600 }}>$99/year</span> for life.
            </p>
            <p style={{
              fontFamily: 'var(--font-mono)', fontSize: '12px',
              color: 'var(--blue-primary)', fontWeight: 600,
            }}>{spotsLeft} spots remaining</p>
          </div>
        </div>
      )}

      <div style={{ padding: '16px 28px 40px' }}>
        <button
          onClick={() => { setAuthMode('login'); setShowAuth(true); }}
          style={{
            width: '100%', padding: '14px',
            backgroundColor: 'transparent',
            color: 'var(--text-secondary)',
            border: '1px solid var(--stroke-muted)',
            borderRadius: '14px',
            fontSize: '15px', fontWeight: 500,
            cursor: 'pointer',
            fontFamily: 'var(--font-sans)',
          }}
        >
          Sign in
        </button>
      </div>

      {showAuth && <AuthModal onClose={() => setShowAuth(false)} initialMode={authMode} />}
    </div>
  );
}

function ProofDot() {
  return <div style={{ width: '3px', height: '3px', borderRadius: '50%', background: 'var(--text-tertiary)', opacity: 0.4 }} />;
}

function ValueProp({ title, desc }) {
  return (
    <div style={{
      backgroundColor: 'var(--surface-1)',
      border: '1px solid var(--stroke-subtle)',
      borderRadius: '16px',
      padding: '20px',
    }}>
      <h3 style={{
        fontFamily: 'var(--font-serif)',
        fontSize: '15px', fontWeight: 600,
        color: 'var(--text-primary)',
        marginBottom: '6px',
      }}>{title}</h3>
      <p style={{
        fontSize: '13px',
        color: 'var(--text-secondary)',
        lineHeight: '1.55',
      }}>{desc}</p>
    </div>
  );
}

function LandingStat({ label, value, color }) {
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{
        fontFamily: 'var(--font-mono)',
        fontSize: '20px', fontWeight: 700,
        color: color || 'var(--text-primary)',
      }}>{value}</div>
      <div style={{
        fontSize: '10px', color: 'var(--text-tertiary)',
        textTransform: 'uppercase', letterSpacing: '0.05em',
        marginTop: '4px',
      }}>{label}</div>
    </div>
  );
}

src/components/sharp/ResolutionScreen.js.content:
export default function ResolutionScreen({ pick, onBack }) {
  const isWin = pick?.result === 'win';
  const isPush = pick?.result === 'push';
  const accentColor = isPush ? 'var(--text-secondary)' : isWin ? 'var(--green-profit)' : 'var(--red-loss)';
  const resultLabel = isPush ? 'Push' : isWin ? 'Win' : 'Loss';
  const profitDisplay = pick?.profit_units != null
    ? `${pick.profit_units >= 0 ? '+' : ''}${pick.profit_units}u`
    : '--';
  const hasScore = pick?.home_score != null && pick?.away_score != null;

  return (
    <div style={{ padding: '0', paddingBottom: '100px' }}>
      <div style={{
        padding: '16px 20px',
        display: 'flex', alignItems: 'center', gap: '12px',
      }}>
        <button onClick={onBack} style={{
          background: 'none', border: 'none', cursor: 'pointer',
          color: 'var(--text-secondary)', padding: '4px',
        }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M19 12H5M12 19l-7-7 7-7"/>
          </svg>
        </button>
        <span style={{
          fontFamily: 'var(--font-sans)', fontSize: '16px', fontWeight: 600,
          color: 'var(--text-primary)',
        }}>Outcome Resolved</span>
      </div>

      <div style={{ padding: '0 20px' }}>
        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '20px',
          border: '1px solid var(--stroke-subtle)', padding: '24px',
          marginBottom: '16px', textAlign: 'center',
        }}>
          <div style={{
            width: '56px', height: '56px', borderRadius: '50%',
            backgroundColor: isPush ? 'rgba(255,255,255,0.05)' : isWin ? 'rgba(34, 197, 94, 0.1)' : 'rgba(239, 68, 68, 0.1)',
            border: `2px solid ${accentColor}`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            margin: '0 auto 16px',
          }}>
            {isPush ? (
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={accentColor} strokeWidth="2.5" strokeLinecap="round">
                <line x1="6" y1="12" x2="18" y2="12"/>
              </svg>
            ) : isWin ? (
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={accentColor} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="20 6 9 17 4 12"/>
              </svg>
            ) : (
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={accentColor} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <line x1="18" y1="6" x2="6" y2="18"/>
                <line x1="6" y1="6" x2="18" y2="18"/>
              </svg>
            )}
          </div>

          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '12px', fontWeight: 600,
            letterSpacing: '2px', textTransform: 'uppercase',
            color: accentColor, marginBottom: '8px',
          }}>{resultLabel}</div>

          <div style={{
            fontFamily: 'var(--font-serif)', fontSize: '22px', fontWeight: 600,
            color: 'var(--text-primary)', marginBottom: '6px',
          }}>
            {pick?.away_team} @ {pick?.home_team}
          </div>

          {hasScore && (
            <div style={{
              fontFamily: 'var(--font-mono)', fontSize: '16px', fontWeight: 600,
              color: 'var(--text-primary)', marginBottom: '8px',
            }}>
              {pick.away_score} – {pick.home_score}
            </div>
          )}

          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '14px',
            color: 'var(--text-secondary)', marginBottom: '16px',
          }}>
            {pick?.side} {pick?.line > 0 ? `+${pick.line}` : pick?.line}
            {pick?.market_odds ? ` (${pick.market_odds > 0 ? '+' : ''}${pick.market_odds})` : ''}
          </div>

          <div style={{
            fontFamily: 'var(--font-mono)', fontSize: '36px', fontWeight: 700,
            color: accentColor,
          }}>{profitDisplay}</div>
        </div>

        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '16px',
          border: '1px solid var(--stroke-subtle)', padding: '20px',
          marginBottom: '16px',
        }}>
          <h3 style={{
            fontFamily: 'var(--font-sans)', fontSize: '15px', fontWeight: 600,
            color: 'var(--text-primary)', marginBottom: '12px',
          }}>Process Review</h3>
          <p style={{
            fontSize: '14px', color: 'var(--text-secondary)', lineHeight: '1.7',
            marginBottom: '16px',
          }}>
            {isPush
              ? `The spread landed exactly on the number. Your wager is returned — no win, no loss. The edge was ${pick?.edge_pct || '--'}% at entry. A push is variance doing what variance does.`
              : isWin
              ? `This outcome was within the model's expected range. The edge was ${pick?.edge_pct || '--'}% — meaning a win was expected roughly ${Math.round(50 + (pick?.edge_pct || 0))}% of the time. This result confirms the process, but one win does not validate a model.`
              : `This outcome was within the model's expected range. The edge was ${pick?.edge_pct || '--'}% — meaning a loss was expected roughly ${Math.round(50 - (pick?.edge_pct || 0))}% of the time. A single loss does not invalidate the model.`
            }
          </p>

          <div style={{
            display: 'flex', justifyContent: 'space-around',
            padding: '16px 0', borderTop: '1px solid var(--stroke-subtle)',
          }}>
            <ContextStat value={`${pick?.edge_pct || '--'}%`} label="Edge at entry" />
            <ContextStat value={`${Math.round(50 + (pick?.edge_pct || 0))}%`} label="Win probability" />
            <ContextStat value={pick?.season_record || '--'} label="Season record" />
          </div>
        </div>

        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '16px',
          border: '1px solid var(--stroke-subtle)', padding: '20px',
          marginBottom: '16px',
        }}>
          <h3 style={{
            fontFamily: 'var(--font-sans)', fontSize: '15px', fontWeight: 600,
            color: 'var(--text-primary)', marginBottom: '12px',
          }}>What Discipline Looks Like Now</h3>
          <p style={{
            fontSize: '14px', color: 'var(--text-secondary)', lineHeight: '1.7',
          }}>
            {isPush
              ? 'A push changes nothing. No adjustment needed. The process identified an edge, the game landed on the number. The next pick comes when the edge is there.'
              : isWin
              ? 'The correct response to a win is the same as a loss: nothing. No expanding your criteria. No overconfidence. The next pick comes when the edge is there.'
              : 'The correct response to a loss is the same as a win: nothing. No revenge bets. No doubling down. No changing your unit size. The next pick comes when the edge is there.'
            }
          </p>
        </div>

        <div style={{
          fontFamily: 'var(--font-serif)', fontStyle: 'italic', fontSize: '14px',
          color: 'var(--text-secondary)', textAlign: 'center',
          padding: '16px 0 8px', lineHeight: '1.5',
        }}>
          {isPush
            ? "A push is neither validation nor failure. The number landed exactly where the market set it."
            : isWin
            ? "A win doesn't mean you were right. It means the probability played out."
            : "A loss doesn't mean the model failed. It means variance occurred within expected parameters."
          }
        </div>

        <p style={{
          fontSize: '11px', color: 'var(--text-tertiary)', textAlign: 'center',
          padding: '4px 0 16px', lineHeight: '1.5',
        }}>
          Past performance does not guarantee future results.
        </p>
      </div>
    </div>
  );
}

function ContextStat({ value, label }) {
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{
        fontFamily: 'var(--font-mono)', fontSize: '18px', fontWeight: 600,
        color: 'var(--text-primary)', marginBottom: '4px',
      }}>{value}</div>
      <div style={{
        fontSize: '10px', color: 'var(--text-tertiary)',
        textTransform: 'uppercase', letterSpacing: '0.05em',
      }}>{label}</div>
    </div>
  );
}

src/components/sharp/ReferralScreen.jsx.content:
import { useState } from 'react';
import { useAuth } from '../../hooks/useAuth';

export default function ReferralScreen({ onBack }) {
  const { user } = useAuth();
  const [copied, setCopied] = useState(false);

  const referralCode = user?.referral_code || 'SHARP-XXXX';
  const referralLink = `${window.location.origin}/?ref=${referralCode}`;

  const copyCode = () => {
    navigator.clipboard.writeText(referralLink).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) {
    return (
      <div style={{ padding: '0' }}>
        <ScreenHeader onBack={onBack} />
        <div style={{ padding: '40px 20px', textAlign: 'center' }}>
          <p style={{ color: 'var(--text-secondary)', fontSize: '14px' }}>
            Sign in to access your referral code
          </p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ padding: '0' }}>
      <ScreenHeader onBack={onBack} />

      <div style={{ padding: '0 20px' }}>
        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '16px',
          padding: '32px 24px', border: '1px solid var(--stroke-subtle)',
          textAlign: 'center', marginBottom: '12px',
        }}>
          <div style={{
            width: '56px', height: '56px', borderRadius: '14px',
            backgroundColor: 'var(--surface-2)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            margin: '0 auto 20px',
          }}>
            <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="var(--blue-primary)" strokeWidth="2">
              <path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/>
              <circle cx="9" cy="7" r="4"/>
              <line x1="19" y1="8" x2="19" y2="14"/>
              <line x1="22" y1="11" x2="16" y2="11"/>
            </svg>
          </div>

          <h2 style={{
            fontFamily: 'var(--font-serif)', fontSize: '22px',
            fontWeight: 600, color: 'var(--text-primary)', marginBottom: '8px',
          }}>Refer a friend</h2>
          <p style={{
            fontSize: '14px', color: 'var(--text-secondary)',
            lineHeight: '1.6', marginBottom: '24px', maxWidth: '300px',
            margin: '0 auto 24px',
          }}>
            Share your referral link. When someone subscribes, you both get 14 days of free access.
          </p>

          <div style={{
            backgroundColor: 'var(--surface-2)', borderRadius: '12px',
            padding: '16px', marginBottom: '16px',
          }}>
            <div style={{
              fontFamily: 'var(--font-mono)', fontSize: '18px',
              fontWeight: 700, color: 'var(--blue-primary)', marginBottom: '4px',
            }}>{referralCode}</div>
            <div style={{
              fontSize: '12px', color: 'var(--text-tertiary)',
              wordBreak: 'break-all',
            }}>{referralLink}</div>
          </div>

          <button onClick={copyCode} style={{
            width: '100%', padding: '14px',
            backgroundColor: copied ? 'var(--green-dark)' : 'var(--blue-primary)',
            color: '#fff', border: 'none', borderRadius: '10px',
            fontSize: '15px', fontWeight: 600, cursor: 'pointer',
            fontFamily: 'var(--font-sans)',
            transition: 'background-color 0.2s',
          }}>
            {copied ? 'Copied' : 'Copy Referral Link'}
          </button>
        </div>

        <div style={{
          backgroundColor: 'var(--surface-1)', borderRadius: '16px',
          padding: '20px', border: '1px solid var(--stroke-subtle)',
        }}>
          <h3 style={{
            fontSize: '12px', fontWeight: 600, color: 'var(--text-tertiary)',
            textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '16px',
          }}>How it works</h3>

          {[
            { step: '1', text: 'Share your unique referral link with friends' },
            { step: '2', text: 'They sign up and start a paid subscription' },
            { step: '3', text: 'You both receive 14 days of free access' },
          ].map(item => (
            <div key={item.step} style={{
              display: 'flex', alignItems: 'center', gap: '14px',
              padding: '10px 0',
              borderBottom: item.step !== '3' ? '1px solid var(--stroke-subtle)' : 'none',
            }}>
              <div style={{
                width: '28px', height: '28px', borderRadius: '8px',
                backgroundColor: 'var(--surface-2)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontFamily: 'var(--font-mono)', fontSize: '13px',
                fontWeight: 600, color: 'var(--blue-primary)',
                flexShrink: 0,
              }}>{item.step}</div>
              <span style={{
                fontSize: '13px', color: 'var(--text-secondary)',
              }}>{item.text}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function ScreenHeader({ onBack }) {
  return (
    <div style={{
      padding: '20px 20px 16px', display: 'flex', alignItems: 'center', gap: '12px',
    }}>
      <button onClick={onBack} style={{
        background: 'none', border: 'none', cursor: 'pointer',
        color: 'var(--text-secondary)', padding: '4px',
      }}>
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
          <polyline points="15 18 9 12 15 6"/>
        </svg>
      </button>
      <h1 style={{
        fontFamily: 'var(--font-serif)', fontSize: '22px',
        fontWeight: 600, color: 'var(--text-primary)',
      }}>Referral Program</h1>
    </div>
  );
}

