          </div>

          <div style={{
            marginTop: '20px', paddingTop: '16px',
            borderTop: '1px solid var(--stroke-subtle)',
          }}>
            <p style={{
              fontSize: '13px', color: 'var(--text-secondary)', lineHeight: '1.5',
