@legal_bp.route('/legal/privacy')
def privacy():
    body = """
  <h2>What We Collect</h2>
  <p>Sharp Picks collects only the data necessary to operate the product and improve your experience:</p>
  <ul>
    <li><strong>Account information:</strong> Email address, password (hashed), display name</li>
